Promise -> {
  T <- none
  E <- String
  -> Pending:
  -> Resolved:
  -> Rejected:
}

Resolved -> { T:value }
Rejected -> { E:error }

Resolve -> { T:value }
Reject -> { E:error }

runPromise -> {
  Promise:p
  Resolve -< e {
    -> Resolved{value -> e.value}
  }
  Reject -< e {
    -> Rejected{error -> e.error}
  }
  -> p ? {
    Resolved:(r) -> r.value
    Rejected: -> none
    -> none
  }
}
